:root {
  /* Colors */
  --color-black: #000000;
  --color-white: #ffffff;
  --color-blue: #0066ff;
  --color-pink: #ff2d6f;
  --color-green: #39ff14;
  --color-amber: #ffb800;
  --color-red: #ff0000;

  /* Grays */
  --color-gray-900: #111111;
  --color-gray-800: #222222;
  --color-gray-700: #333333;
  --color-gray-500: #666666;
  --color-gray-300: #999999;
  --color-gray-100: #e5e5e5;

  /* Typography */
  --font-mono: "JetBrains Mono", monospace;
  --font-sans: system-ui, -apple-system, "Segoe UI", sans-serif;
  --text-2xs: 9px;
  --text-xs: 10px;
  --text-sm: 12px;
  --text-base: 14px;
  --text-lg: 16px;
  --text-xl: 20px;
  --text-2xl: 24px;
  --text-3xl: 32px;
  --text-4xl: 48px;

  /* Spacing (8px grid with 4px half-step) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 12px;
  --space-4: 16px;
  --space-6: 24px;
  --space-8: 32px;
  --space-12: 48px;
  --space-16: 64px;

  /* Semantic Colors */
  --color-success: var(--color-green);
  --color-warning: var(--color-amber);
  --color-error: var(--color-red);

  /* State Colors */
  --color-hover: var(--color-gray-700);
  --color-disabled: var(--color-gray-500);

  /* Borders */
  --border-width: 2px;
  --border-color: var(--color-gray-700);
  --border: var(--border-width) solid var(--border-color);

  /* Shadows */
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.5);
  --shadow-md: 0 2px 8px rgba(0, 0, 0, 0.6);
  --shadow-lg: 0 4px 16px rgba(0, 0, 0, 0.7);

  /* Z-Index Scale */
  --z-base: 0;
  --z-dropdown: 100;
  --z-sticky: 200;
  --z-overlay: 300;
  --z-modal: 400;
  --z-popover: 500;
  --z-tooltip: 600;
  --z-context-menu: 700;

  /* Focus */
  --focus-ring: 2px solid var(--color-blue);
  --focus-offset: 2px;

  /* Transitions */
  --transition-fast: 100ms;
  --transition-normal: 200ms;
}

export function CrossOriginError(): React.JSX.Element {
  return (
    <div
      role="alert"
      style={{
        position: "fixed",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        backgroundColor: "#000",
        color: "#fff",
        fontFamily: "JetBrains Mono, monospace",
        padding: "32px",
      }}
    >
      <div style={{ maxWidth: "480px", textAlign: "center" }}>
        <h1
          style={{ fontSize: "24px", marginBottom: "16px", color: "#ff3333" }}
        >
          Cross-Origin Isolation Required
        </h1>
        <p style={{ fontSize: "14px", lineHeight: 1.6 }}>
          BRUTALWAV requires <code>SharedArrayBuffer</code> for real-time audio
          processing. Your server must set these headers:
        </p>
        <pre
          style={{
            textAlign: "left",
            backgroundColor: "#111",
            padding: "16px",
            marginTop: "16px",
            fontSize: "12px",
            border: "2px solid #333",
          }}
        >
          {`Cross-Origin-Opener-Policy: same-origin\nCross-Origin-Embedder-Policy: require-corp`}
        </pre>
      </div>
    </div>
  );
}

