1	/**
2	 * Modulation Matrix panel: drag-to-connect UI with SVG cable visualization.
3	 * Source list on left, destination list on right.
4	 * Active routes shown as colored cables with amount controls.
5	 */
6	
7	import { useCallback, useEffect, useRef, useState } from "react";
8	import { tokens } from "@ui/tokens/tokens";
9	import {
10	  useModulationStore,
11	  MOD_SOURCE_LABELS,
12	  MOD_DEST_LABELS,
13	} from "@state/synth/modulation-store";
14	import {
15	  MOD_SOURCES,
16	  MOD_DESTINATIONS,
17	  type ModSource,
18	  type ModDestination,
19	} from "@audio/synth/modulation-types";
20	
21	import type { ModRoute } from "@audio/synth/modulation-types";
22	
23	type Props = {
24	  trackId: string;
25	};
26	
27	const EMPTY_ROUTES: readonly ModRoute[] = [];
28	
29	const BORDER = "var(--border)";
30	
31	const LABEL_STYLE: React.CSSProperties = {
32	  fontFamily: tokens.font.mono,
33	  fontSize: tokens.text.xs,
34	  color: tokens.color.gray300,
35	  textTransform: "uppercase",
36	  letterSpacing: "0.1em",
37	};
38	
39	// Cable colors per source (cycle through for visual distinction)
40	const SOURCE_COLORS: Record<ModSource, string> = {
41	  lfo1: tokens.color.blue,
42	  lfo2: tokens.color.pink,
43	  ampEnv: tokens.color.amber,
44	  filterEnv: tokens.color.green,
45	  velocity: "#ff6600",
46	  aftertouch: "#cc44ff",
47	  modWheel: "#00ccff",
48	  pitchBend: "#ff4488",
49	};
50	
51	function Port({
52	  testId,
53	  color,
54	  onMouseDown,
55	  onMouseUp,
56	}: {
57	  testId: string;
58	  color: string;
59	  onMouseDown?: () => void;
60	  onMouseUp?: () => void;
61	}): React.JSX.Element {
62	  return (
63	    <div
64	      data-testid={testId}
65	      onMouseDown={onMouseDown}
66	      onMouseUp={onMouseUp}
67	      style={{
68	        width: 12,
69	        height: 12,
70	        borderRadius: "50%",
71	        border: `2px solid ${color}`,
72	        backgroundColor: tokens.color.gray900,
73	        cursor: "pointer",
74	        flexShrink: 0,
75	      }}
76	    />
77	  );
78	}
79	
80	export function ModulationMatrix({ trackId }: Props): React.JSX.Element {
81	  const routes = useModulationStore(
82	    (s) => s.matrices[trackId]?.routes ?? EMPTY_ROUTES,
83	  );
84	  const initMatrix = useModulationStore((s) => s.initMatrix);
85	  const addRoute = useModulationStore((s) => s.addRoute);
86	  const removeRoute = useModulationStore((s) => s.removeRoute);
87	  const updateAmount = useModulationStore((s) => s.updateRouteAmount);
88	  const toggleBipolar = useModulationStore((s) => s.toggleRouteBipolar);
89	
90	  useEffect(() => {
91	    initMatrix(trackId);
92	  }, [trackId, initMatrix]);
93	
94	  const [dragSource, setDragSource] = useState<ModSource | null>(null);
95	  const containerRef = useRef<HTMLDivElement>(null);
96	
97	  const handleSrcMouseDown = useCallback((source: ModSource) => {
98	    setDragSource(source);
99	  }, []);
100	
101	  const handleDestMouseUp = useCallback(
102	    (destination: ModDestination) => {
103	      if (dragSource) {
104	        addRoute(trackId, dragSource, destination);
105	        setDragSource(null);
106	      }
107	    },
108	    [dragSource, trackId, addRoute],
109	  );
110	
111	  const handleGlobalMouseUp = useCallback(() => {
112	    setDragSource(null);
113	  }, []);
114	
115	  // Clear drag state when mouse released anywhere (including outside component)
116	  useEffect(() => {
117	    document.addEventListener("mouseup", handleGlobalMouseUp);
118	    return () => {
119	      document.removeEventListener("mouseup", handleGlobalMouseUp);
120	    };
121	  }, [handleGlobalMouseUp]);
122	
123	  return (
124	    <div
125	      ref={containerRef}
126	      data-testid="mod-matrix"
127	      onMouseUp={handleGlobalMouseUp}
128	      style={{
129	        display: "flex",
130	        flexDirection: "column",
131	        gap: tokens.space[2],
132	        border: BORDER,
133	        padding: tokens.space[2],
134	        backgroundColor: tokens.color.gray900,
135	        fontFamily: tokens.font.mono,
136	        fontSize: tokens.text.sm,
137	        color: tokens.color.gray100,
138	        userSelect: "none",
139	      }}
140	    >
141	      <span
142	        style={{
143	          ...LABEL_STYLE,
144	          color: tokens.color.blue,
145	          fontSize: tokens.text.sm,
146	        }}
147	      >
148	        MOD MATRIX
149	      </span>
150	
151	      {/* Sources and Destinations side by side */}
152	      <div style={{ display: "flex", gap: tokens.space[4] }}>
153	        {/* Sources */}
154	        <div
155	          style={{
156	            display: "flex",
157	            flexDirection: "column",
158	            gap: tokens.space[1],
159	          }}
160	        >
161	          <span style={LABEL_STYLE}>SOURCES</span>
162	          {MOD_SOURCES.map((src) => (
163	            <div
164	              key={src}
165	              style={{
166	                display: "flex",
167	                alignItems: "center",
168	                gap: tokens.space[1],
169	              }}
170	            >
171	              <span
172	                style={{
173	                  ...LABEL_STYLE,
174	                  width: 80,
175	                  color:
176	                    dragSource === src
177	                      ? SOURCE_COLORS[src]
178	                      : tokens.color.gray300,
179	                }}
180	              >
181	                {MOD_SOURCE_LABELS[src]}
182	              </span>
183	              <Port
184	                testId={`src-port-${src}`}
185	                color={SOURCE_COLORS[src]}
186	                onMouseDown={() => {
187	                  handleSrcMouseDown(src);
188	                }}
189	              />
190	            </div>
191	          ))}
192	        </div>
193	
194	        {/* SVG cable visualization area */}
195	        <div style={{ position: "relative", width: 60, minHeight: 200 }}>
196	          <svg
197	            viewBox="0 0 60 200"
198	            preserveAspectRatio="none"
199	            style={{
200	              position: "absolute",
201	              top: 0,
202	              left: 0,
203	              width: "100%",
204	              height: "100%",
205	              pointerEvents: "none",
206	            }}
207	          >
208	            {routes.map((route) => {
209	              const srcIdx = MOD_SOURCES.indexOf(route.source);
210	              const destIdx = MOD_DESTINATIONS.indexOf(route.destination);
211	              const srcY = 20 + srcIdx * 22;
212	              const destY = 20 + destIdx * 22;
213	              return (
214	                <line
215	                  key={route.id}
216	                  data-testid={`cable-${route.source}-${route.destination}`}
217	                  x1={0}
218	                  y1={srcY}
219	                  x2={60}
220	                  y2={destY}
221	                  stroke={SOURCE_COLORS[route.source]}
222	                  strokeWidth={2}
223	                  strokeOpacity={0.7 + Math.abs(route.amount) * 0.3}
224	                />
225	              );
226	            })}
227	          </svg>
228	        </div>
229	
230	        {/* Destinations */}
231	        <div
232	          style={{
233	            display: "flex",
234	            flexDirection: "column",
235	            gap: tokens.space[1],
236	          }}
237	        >
238	          <span style={LABEL_STYLE}>DESTINATIONS</span>
239	          {MOD_DESTINATIONS.map((dest) => (
240	            <div
241	              key={dest}
242	              style={{
243	                display: "flex",
244	                alignItems: "center",
245	                gap: tokens.space[1],
246	              }}
247	            >
248	              <Port
249	                testId={`dest-port-${dest}`}
250	                color={tokens.color.gray500}
251	                onMouseUp={() => {
252	                  handleDestMouseUp(dest);
253	                }}
254	              />
255	              <span style={{ ...LABEL_STYLE, width: 80 }}>
256	                {MOD_DEST_LABELS[dest]}
257	              </span>
258	            </div>
259	          ))}
260	        </div>
261	      </div>
262	
263	      {/* Active routes list with amount controls */}
264	      {routes.length > 0 && (
265	        <div
266	          style={{
267	            display: "flex",
268	            flexDirection: "column",
269	            gap: tokens.space[1],
270	            borderTop: BORDER,
271	            paddingTop: tokens.space[2],
272	          }}
273	        >
274	          <span style={LABEL_STYLE}>ROUTES</span>
275	          {routes.map((route) => (
276	            <div
277	              key={route.id}
278	              style={{
279	                display: "flex",
280	                alignItems: "center",
281	                gap: tokens.space[2],
282	                padding: "2px 0",
283	              }}
284	            >
285	              <span
286	                style={{
287	                  ...LABEL_STYLE,
288	                  color: SOURCE_COLORS[route.source],
289	                  width: 80,
290	                }}
291	              >
292	                {MOD_SOURCE_LABELS[route.source]}
293	              </span>
294	              <span style={{ ...LABEL_STYLE, color: tokens.color.gray500 }}>
295	                {">"}
296	              </span>
297	              <span style={{ ...LABEL_STYLE, width: 80 }}>
298	                {MOD_DEST_LABELS[route.destination]}
299	              </span>
300	              <input
301	                type="range"
302	                data-testid={`route-amount-${route.id}`}
303	                min={-1}
304	                max={1}
305	                step={0.01}
306	                value={route.amount}
307	                onChange={(e) => {
308	                  updateAmount(trackId, route.id, Number(e.target.value));
309	                }}
310	                style={{ width: 80, accentColor: SOURCE_COLORS[route.source] }}
311	              />
312	              <span style={{ ...LABEL_STYLE, width: 40, textAlign: "right" }}>
313	                {(route.amount * 100).toFixed(0)}%
314	              </span>
315	              <button
316	                data-testid={`route-bipolar-${route.id}`}
317	                onClick={() => {
318	                  toggleBipolar(trackId, route.id);
319	                }}
320	                style={{
321	                  background: "none",
322	                  border: `${String(tokens.border.width)}px solid ${route.bipolar ? tokens.color.blue : tokens.color.gray700}`,
323	                  color: route.bipolar
324	                    ? tokens.color.blue
325	                    : tokens.color.gray500,
326	                  fontFamily: tokens.font.mono,
327	                  fontSize: tokens.text["2xs"],
328	                  cursor: "pointer",
329	                  padding: "1px 3px",
330	                }}
331	              >
332	                {route.bipolar ? "BI" : "UNI"}
333	              </button>
334	              <button
335	                data-testid={`route-delete-${route.id}`}
336	                onClick={() => {
337	                  removeRoute(trackId, route.id);
338	                }}
339	                style={{
340	                  background: "none",
