1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import { Toolbar } from "./Toolbar";
3	import { ArrangementPanel } from "@ui/arrangement";
4	import { InstrumentPanel } from "./panels";
5	import { MixerPanel } from "./mixer";
6	import { MediaPoolPanel } from "./media-pool/MediaPoolPanel";
7	import { CommandRegistry } from "./keyboard/command-registry";
8	import { ShortcutMap } from "./keyboard/shortcut-map";
9	import { useKeyboardShortcuts } from "./keyboard/useKeyboardShortcuts";
10	import { useTransportShortcuts } from "./transport/useTransportShortcuts";
11	import { useSessionShortcuts } from "./session/useSessionShortcuts";
12	import { RecoveryDialog } from "./session/RecoveryDialog";
13	import { TransportProvider } from "@audio/transport-provider";
14	import { EffectsBridgeProvider } from "@audio/effects/EffectsBridgeProvider";
15	import { RoutingBridgeProvider } from "@audio/mixer/RoutingBridgeProvider";
16	import { useMediaPool } from "@audio/media-pool/use-media-pool";
17	import { sharedUndoManager } from "@state/undo/shared-undo-manager";
18	import { useSessionPersistence } from "@state/session/use-session-persistence";
19	import type { SessionStorage } from "@state/session/session-storage";
20	import { createDefaultSession } from "@state/session/session-schema";
21	import { hydrateStore } from "@state/session/use-session-persistence";
22	import { ErrorBoundary } from "./ErrorBoundary";
23	import { KeyboardShortcutsPanel } from "./keyboard/KeyboardShortcutsPanel";
24	import { ActionToast } from "./primitives/ActionToast";
25	
26	function DawShellInner({
27	  sessionStorage,
28	  idbWarning,
29	}: {
30	  sessionStorage: SessionStorage;
31	  idbWarning: boolean;
32	}): React.JSX.Element {
33	  const registry = useMemo(() => new CommandRegistry(), []);
34	  const shortcuts = useMemo(() => new ShortcutMap(), []);
35	  const pool = useMediaPool();
36	  const undoManager = sharedUndoManager;
37	  const { saveNow, recoveryWarnings } = useSessionPersistence(sessionStorage);
38	  const [dismissed, setDismissed] = useState(false);
39	  const [shortcutsOpen, setShortcutsOpen] = useState(false);
40	  const [toastMessage, setToastMessage] = useState<string | null>(null);
41	  const toastCountRef = useRef(0);
42	  const showRecovery = !dismissed && recoveryWarnings.length > 0;
43	
44	  const stableSaveNow = useCallback(() => saveNow(), [saveNow]);
45	
46	  const showToast = useCallback((msg: string) => {
47	    toastCountRef.current += 1;
48	    setToastMessage(`${msg}#${String(toastCountRef.current)}`);
49	  }, []);
50	
51	  useEffect(() => {
52	    if (idbWarning) {
53	      showToast("Storage unavailable -- changes won't persist");
54	    }
55	  }, [idbWarning, showToast]);
56	
57	  useTransportShortcuts(registry, shortcuts);
58	  useSessionShortcuts(
59	    registry,
60	    shortcuts,
61	    undoManager,
62	    stableSaveNow,
63	    showToast,
64	  );
65	
66	  useEffect(() => {
67	    registry.register({
68	      id: "app.shortcuts-legend",
69	      label: "Toggle Keyboard Shortcuts",
70	      execute: () => {
71	        setShortcutsOpen((prev) => !prev);
72	      },
73	    });
74	    shortcuts.bind({
75	      key: "?",
76	      shift: true,
77	      commandId: "app.shortcuts-legend",
78	    });
79	    return () => {
80	      registry.unregister("app.shortcuts-legend");
81	      shortcuts.unbind("app.shortcuts-legend");
82	    };
83	  }, [registry, shortcuts]);
84	
85	  useKeyboardShortcuts(registry, shortcuts);
86	
87	  return (
88	    <div
89	      data-testid="daw-shell"
90	      style={{
91	        display: "flex",
92	        flexDirection: "column",
93	        height: "100vh",
94	        backgroundColor: "var(--color-black)",
95	      }}
96	    >
97	      <Toolbar />
98	      <ErrorBoundary fallbackLabel="Panel crashed">
99	        <div
100	          style={{
101	            display: "flex",
102	            flexDirection: "column",
103	            flex: 1,
104	            overflow: "hidden",
105	          }}
106	        >
107	          <ArrangementPanel />
108	          <MixerPanel />
109	          <div style={{ display: "flex", overflow: "hidden" }}>
110	            <div style={{ flex: 1 }}>
111	              <InstrumentPanel />
112	            </div>
113	            <div style={{ flex: 1 }}>
114	              <MediaPoolPanel pool={pool} />
115	            </div>
116	          </div>
117	        </div>
118	      </ErrorBoundary>
119	      <KeyboardShortcutsPanel
120	        open={shortcutsOpen}
121	        onClose={() => {
122	          setShortcutsOpen(false);
123	        }}
124	      />
125	      <RecoveryDialog
126	        open={showRecovery}
127	        warnings={recoveryWarnings}
128	        onAccept={() => {
129	          setDismissed(true);
130	        }}
131	        onDiscard={() => {
132	          hydrateStore(createDefaultSession());
133	          setDismissed(true);
134	        }}
135	      />
136	      <ActionToast message={toastMessage} />
137	    </div>
138	  );
139	}
140	
141	export function DawShell({
142	  sessionStorage,
143	  idbWarning = false,
144	}: {
145	  sessionStorage: SessionStorage;
146	  idbWarning?: boolean;
147	}): React.JSX.Element {
148	  return (
149	    <TransportProvider>
150	      <EffectsBridgeProvider>
151	        <RoutingBridgeProvider>
152	          <DawShellInner
153	            sessionStorage={sessionStorage}
154	            idbWarning={idbWarning}
155	          />
156	        </RoutingBridgeProvider>
157	      </EffectsBridgeProvider>
158	    </TransportProvider>
159	  );
160	}
